require("UI.UI_Activity_Hesu")function UIMgr:UI_Activity_Hesu_Create(a)local b;if GameMgr.Inst.prefer_language=='chs'or GameMgr.Inst.prefer_language=='chs_t'then b=LuaTools.LoadPrefab('prefab/ui_output/activity/UI_Activity_Hesu',a)else b=LuaTools.LoadPrefab('prefab/ui_output/activity/UI_Activity_Hesu',a)end;if not b then return nil end;b.gameObject:SetActive(false)local c=UI_Activity_Hesu:Create(b)c.transform:Find("getted"):GetComponent(typeof(UnityEngine.UI.Button)).onClick:AddListener(function()c:OpenHesu()end)c:OnCreate()return c end